  1	import * as React from 'react';
  2	import { projectResource } from '@odf/core/resources';
  3	import { S3ProviderType } from '@odf/core/types';
  4	import ResourceDropdown from '@odf/shared/dropdown/ResourceDropdown';
  5	import { ProjectModel, SecretModel } from '@odf/shared/models';
  6	import { getName } from '@odf/shared/selectors';
  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import { getValidWatchK8sResourceObj } from '@odf/shared/utils';
  9	import {
 10	  K8sResourceCommon,
 11	  k8sGet,
 12	} from '@openshift-console/dynamic-plugin-sdk';
 13	import {
 14	  FormGroup,
 15	  Checkbox,
 16	  Button,
 17	  ButtonVariant,
 18	  Bullseye,
 19	  Stack,
 20	  StackItem,
 21	  TextContent,
 22	  Text,
 23	  TextVariants,
 24	  Alert,
 25	  AlertVariant,
 26	} from '@patternfly/react-core';
 27	import { LockIcon } from '@patternfly/react-icons';
 28	import { StorageType, SecretRef, ClientType } from '../types';
 29	import { hasOBCOwnerRef } from '../utils';
 30	import './loginForm.scss';
 31	
 32	export type LoginFormProps = {
 33	  onLogin: (
 34	    secretRef: SecretRef,
 35	    storageType: StorageType,
 36	    hasOBCOwnerRef?: boolean
 37	  ) => void;
 38	  logout: () => void;
 39	  providerType?: S3ProviderType;
 40	  type?: ClientType;
 41	};
 42	
 43	type LoginBodyProps = {
 44	  secretRef: SecretRef;
 45	  setSecretRef: React.Dispatch<React.SetStateAction<SecretRef>>;
 46	  storageType: StorageType;
 47	  setStorageType: React.Dispatch<React.SetStateAction<StorageType>>;
 48	};
 49	
 50	export const LoginBody: React.FC<LoginBodyProps> = ({
 51	  secretRef,
 52	  setSecretRef,
 53	  storageType,
 54	  setStorageType,
 55	}) => {
 56	  const { t } = useCustomTranslation();
 57	
 58	  const handleChange = (
 59	    _event: React.FormEvent<HTMLInputElement>,
 60	    checked: boolean
 61	  ) => {
 62	    setStorageType(checked ? StorageType.Local : StorageType.Session);
 63	  };
 64	
 65	  return (
 66	    <>
 67	      <FormGroup
 68	        label={t('Secret namespace')}
 69	        className="pf-v6-u-my-md"
 70	        isRequired
 71	      >
 72	        <ResourceDropdown<K8sResourceCommon>
 73	          resource={projectResource}
 74	          resourceModel={ProjectModel}
 75	          onSelect={(ns) => {
 76	            setSecretRef((secret) => ({ ...secret, namespace: getName(ns) }));
 77	          }}
 78	          className="odf-s3-secret__dropdown"
 79	        />
 80	      </FormGroup>
 81	      <FormGroup label={t('Secret name')} className="pf-v6-u-my-md" isRequired>
 82	        <ResourceDropdown<K8sResourceCommon>
 83	          resource={getValidWatchK8sResourceObj(
 84	            {
 85	              kind: SecretModel.kind,
 86	              namespace: secretRef.namespace,
 87	              isList: true,
 88	            },
 89	            !!secretRef.namespace
 90	          )}
 91	          resourceModel={SecretModel}
 92	          onSelect={(n) => {
 93	            setSecretRef((secret) => ({ ...secret, name: getName(n) }));
 94	          }}
 95	          className="odf-s3-secret__dropdown"
 96	          isDisabled={!secretRef.namespace}
 97	        />
 98	      </FormGroup>
 99	      <Checkbox
100	        id="storage-type"
101	        className="pf-v6-u-my-md"
102	        label={t('Stay signed in')}
103	        description={t(
104	          'If not selected, you need to sign in again when you open a new browser window or a tab.'
105	        )}
106	        isChecked={storageType === StorageType.Local}
107	        onChange={handleChange}
108	      />
109	    </>
110	  );
111	};
112	
113	export const LoginForm: React.FC<LoginFormProps> = ({
114	  onLogin,
115	  logout,
116	  type = ClientType.S3,
117	}) => {
118	  const { t } = useCustomTranslation();
119	
120	  const [secretRef, setSecretRef] = React.useState<SecretRef>({
121	    name: '',
122	    namespace: '',
123	  });
124	  const [storageType, setStorageType] = React.useState<StorageType>(
125	    StorageType.Session
126	  );
127	  const [isLoading, setIsLoading] = React.useState(false);
128	  const [error, setError] = React.useState<string | null>(null);
129	
130	  const storeCredentials = async () => {
131	    if (!secretRef.name || !secretRef.namespace) {
132	      return;
133	    }
134	
135	    setIsLoading(true);
136	    setError(null);
137	
138	    try {
139	      const secret = await k8sGet({
140	        model: SecretModel,
141	        name: secretRef.name,
142	        ns: secretRef.namespace,
143	      });
144	
145	      const obcOwnerRef = hasOBCOwnerRef(secret);
146	
147	      // Block login from IAM tab if Secret has OBC owner reference
148	      if (obcOwnerRef && type === ClientType.IAM) {
149	        setError(
150	          t(
151	            'IAM is not supported for ObjectBucketClaim accounts. Please select a different Secret.'
152	          )
153	        );
154	        setIsLoading(false);
155	        return;
156	      }
157	
158	      logout();
159	      onLogin(secretRef, storageType, obcOwnerRef);
160	    } catch (err) {
161	      setError(
162	        err?.message ||
163	          t(
164	            'Failed to fetch Secret. Please check the Secret name and namespace.'
165	          )
166	      );
167	    } finally {
168	      setIsLoading(false);
169	    }
170	  };
171	
172	  return (
173	    <Bullseye className="pf-v6-u-mt-lg">
174	      <Stack hasGutter>
175	        <StackItem>
176	          <TextContent className="pf-v6-u-text-align-center">
177	            <Text component={TextVariants.h3}>
178	              <LockIcon className="pf-v6-u-mr-xs" />
179	              {t('Sign in to continue')}
180	            </Text>
181	            <Text component={TextVariants.small}>
182	              {t(
183	                'You need permission to access buckets on this cluster. Use Secret namespace and Secret name to continue'
184	              )}
185	            </Text>
186	          </TextContent>
187	        </StackItem>
188	        <StackItem>
189	          {error && (
190	            <Alert
191	              variant={AlertVariant.danger}
192	              title={error}
193	              isInline
194	              className="pf-v6-u-my-md"
195	            />
196	          )}
197	        </StackItem>
198	        <StackItem>
199	          <LoginBody
200	            secretRef={secretRef}
201	            setSecretRef={setSecretRef}
202	            storageType={storageType}
203	            setStorageType={setStorageType}
204	          />
205	        </StackItem>
206	        <StackItem className="pf-v6-u-text-align-center">
207	          <Button
208	            variant={ButtonVariant.primary}
209	            onClick={storeCredentials}
210	            isDisabled={!secretRef.name || !secretRef.namespace || isLoading}
211	            isLoading={isLoading}
212	          >
213	            {t('Sign in')}
214	          </Button>
215	        </StackItem>
216	      </Stack>
217	    </Bullseye>
218	  );
219	};
220	
221	export default LoginForm;

