 69	        isRequired
 70	      >
 71	        <ResourceDropdown<K8sResourceCommon>
 72	          resource={projectResource}
 73	          resourceModel={ProjectModel}
 74	          onSelect={(ns) => {
 75	            setSecretRef((secret) => ({ ...secret, namespace: getName(ns) }));
 76	          }}
 77	          className="odf-s3-secret__dropdown"
 78	        />
 79	      </FormGroup>
 80	      <FormGroup label={t('Secret name')} className="pf-v6-u-my-md" isRequired>
 81	        <ResourceDropdown<K8sResourceCommon>
 82	          resource={getValidWatchK8sResourceObj(
 83	            {
 84	              kind: SecretModel.kind,
 85	              namespace: secretRef.namespace,
 86	              isList: true,
 87	            },
 88	            !!secretRef.namespace
 89	          )}
 90	          resourceModel={SecretModel}
 91	          onSelect={(n) => {
 92	            setSecretRef((secret) => ({ ...secret, name: getName(n) }));
 93	          }}
 94	          className="odf-s3-secret__dropdown"
 95	          isDisabled={!secretRef.namespace}
 96	        />
 97	      </FormGroup>
 98	      <Checkbox
 99	        id="storage-type"
100	        className="pf-v6-u-my-md"
101	        label={t('Stay signed in')}
102	        description={t(
103	          'If not selected, you need to sign in again when you open a new browser window or a tab.'
104	        )}
105	        isChecked={storageType === StorageType.Local}
106	        onChange={handleChange}
107	      />
108	    </>
109	  );
110	};
