112	export const LoginForm: React.FC<LoginFormProps> = ({
113	  onLogin,
114	  logout,
115	  type = ClientType.S3,
116	}) => {
117	  const { t } = useCustomTranslation();
118	
119	  const [secretRef, setSecretRef] = React.useState<SecretRef>({
120	    name: '',
121	    namespace: '',
122	  });
123	  const [storageType, setStorageType] = React.useState<StorageType>(
124	    StorageType.Session
125	  );
126	  const [isLoading, setIsLoading] = React.useState(false);
127	  const [error, setError] = React.useState<string | null>(null);
128	
129	  const storeCredentials = async () => {
130	    if (!secretRef.name || !secretRef.namespace) {
131	      return;
132	    }
133	
134	    setIsLoading(true);
135	    setError(null);
136	
137	    try {
138	      const secret = await k8sGet({
139	        model: SecretModel,
140	        name: secretRef.name,
141	        ns: secretRef.namespace,
142	      });
143	
144	      const obcOwnerRef = hasOBCOwnerRef(secret);
145	
146	      // Block login from IAM tab if Secret has OBC owner reference
147	      if (obcOwnerRef && type === ClientType.IAM) {
148	        setError(
149	          t(
150	            'IAM is not supported for ObjectBucketClaim accounts. Please select a different Secret.'
151	          )
152	        );
153	        setIsLoading(false);
154	        return;
155	      }
156	
157	      logout();
158	      onLogin(secretRef, storageType, obcOwnerRef);
159	    } catch (err) {
160	      setError(
161	        err?.message ||
162	          t(
163	            'Failed to fetch Secret. Please check the Secret name and namespace.'
164	          )
165	      );
166	    } finally {
167	      setIsLoading(false);
168	    }
169	  };
170	
171	  return (
172	    <Bullseye className="pf-v6-u-mt-lg">
173	      <Stack hasGutter>
174	        <StackItem>
175	          <Content className="pf-v6-u-text-align-center">
176	            <Content component={ContentVariants.h3}>
177	              <LockIcon className="pf-v6-u-mr-xs" />
178	              {t('Sign in to continue')}
179	            </Content>
180	            <Content component={ContentVariants.small}>
181	              {t(
182	                'You need permission to access buckets on this cluster. Use Secret namespace and Secret name to continue'
183	              )}
184	            </Content>
185	          </Content>
186	        </StackItem>
187	        <StackItem>
188	          {error && (
189	            <Alert
190	              variant={AlertVariant.danger}
191	              title={error}
192	              isInline
193	              className="pf-v6-u-my-md"
194	            />
195	          )}
196	        </StackItem>
197	        <StackItem>
198	          <LoginBody
199	            secretRef={secretRef}
200	            setSecretRef={setSecretRef}
201	            storageType={storageType}
202	            setStorageType={setStorageType}
203	          />
204	        </StackItem>
205	        <StackItem className="pf-v6-u-text-align-center">
206	          <Button
207	            variant={ButtonVariant.primary}
208	            onClick={storeCredentials}
209	            isDisabled={!secretRef.name || !secretRef.namespace || isLoading}
210	            isLoading={isLoading}
211	          >
212	            {t('Sign in')}
213	          </Button>
214	        </StackItem>
215	      </Stack>
216	    </Bullseye>
217	  );
218	};
219	
220	export default LoginForm;
